@pytest.mark.parametrize("magnitude, snr_goal, expected", test_cases)
def test_basic_calculation(magnitude, snr_goal, expected):
    exp_times, camera = camera_exptime('EAC1', 'G2V Star', magnitude, snr_goal, True)
    assert [q.value for q in exp_times] == pytest.approx(expected)

# def test_print_stuff():
#     print([(mag, snr, [q.value for q in camera_exptime('EAC1', 'G2V Star', mag, snr, True)[0]]) for mag in range(4, 35) for snr in range(3, 10)])

def create_eac(name: str):
    telescope = Telescope()
    telescope.set_from_json(name)
    telescope.add_camera(Camera())
    return telescope
